import React, { useEffect, useState } from 'react';

/* ═══════════════════════════════════════════════════════════════════════════
   TOAST SYSTEM
   ═══════════════════════════════════════════════════════════════════════════ */

const toastListeners = new Set();
let toastId = 0;

export function toast(msg, type = 'info') {
  const id = ++toastId;
  const item = { id, msg, type };
  toastListeners.forEach((fn) => fn(item));
}

export function ToastContainer() {
  const [items, setItems] = useState([]);

  useEffect(() => {
    const onToast = (t) => {
      setItems((prev) => [...prev, t]);
      setTimeout(() => {
        setItems((prev) => prev.filter((x) => x.id !== t.id));
      }, 4000);
    };
    toastListeners.add(onToast);
    return () => toastListeners.delete(onToast);
  }, []);

  const iconMap = {
    success: '✓',
    error: '✕',
    info: 'ℹ',
    warning: '⚠',
  };

  const bgMap = {
    success: 'var(--success)',
    error: 'var(--danger)',
    info: 'var(--primary)',
    warning: 'var(--warning)',
  };

  return (
    <div
      style={{
        position: 'fixed',
        top: 20,
        right: 20,
        zIndex: 20000,
        display: 'flex',
        flexDirection: 'column',
        gap: 10,
        maxWidth: 380,
      }}
    >
      {items.map((t) => (
        <div
          key={t.id}
          style={{
            animation: 'slideInRight 0.3s ease-out',
            background: 'var(--surface)',
            color: 'var(--text-primary)',
            padding: '14px 18px',
            borderRadius: 'var(--radius-lg)',
            borderLeft: `4px solid ${bgMap[t.type] || bgMap.info}`,
            fontSize: 14,
            boxShadow: 'var(--shadow-lg)',
            display: 'flex',
            alignItems: 'center',
            gap: 12,
          }}
        >
          <span
            style={{
              width: 28,
              height: 28,
              borderRadius: 'var(--radius-full)',
              background: `${bgMap[t.type] || bgMap.info}15`,
              color: bgMap[t.type] || bgMap.info,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontWeight: 700,
              fontSize: 13,
              flexShrink: 0,
            }}
          >
            {iconMap[t.type] || iconMap.info}
          </span>
          <span style={{ flex: 1, lineHeight: 1.4 }}>{t.msg}</span>
          <button
            onClick={() => setItems((prev) => prev.filter((x) => x.id !== t.id))}
            style={{
              background: 'none',
              border: 'none',
              color: 'var(--text-muted)',
              cursor: 'pointer',
              fontSize: 16,
              lineHeight: 1,
              padding: 2,
              flexShrink: 0,
            }}
          >
            ×
          </button>
        </div>
      ))}
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   SPINNER
   ═══════════════════════════════════════════════════════════════════════════ */

export function Spinner({ size = 20, color = 'var(--primary)' }) {
  return (
    <span
      style={{
        display: 'inline-block',
        width: size,
        height: size,
        border: `2.5px solid ${color}25`,
        borderTopColor: color,
        borderRadius: '50%',
        animation: 'spin 0.7s linear infinite',
        verticalAlign: 'middle',
      }}
    />
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   BUTTON
   ═══════════════════════════════════════════════════════════════════════════ */

const btnBase = {
  border: 'none',
  borderRadius: 'var(--radius)',
  fontFamily: 'var(--font-body)',
  fontWeight: 500,
  cursor: 'pointer',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  gap: 8,
  transition: 'all 0.15s ease',
  outline: 'none',
};

const variants = {
  primary: {
    background: 'var(--primary)',
    color: 'var(--white)',
  },
  secondary: {
    background: 'var(--surface)',
    color: 'var(--text-primary)',
    border: '1px solid var(--border)',
  },
  ghost: {
    background: 'transparent',
    color: 'var(--text-secondary)',
  },
  danger: {
    background: 'var(--danger)',
    color: 'var(--white)',
  },
  success: {
    background: 'var(--success)',
    color: 'var(--white)',
  },
  outline: {
    background: 'transparent',
    color: 'var(--primary)',
    border: '1px solid var(--primary)',
  },
};

const sizes = {
  xs: { padding: '4px 8px', fontSize: 12 },
  sm: { padding: '6px 14px', fontSize: 13 },
  md: { padding: '9px 18px', fontSize: 14 },
  lg: { padding: '12px 24px', fontSize: 15 },
};

export function Btn({
  variant = 'primary',
  size = 'md',
  loading,
  disabled,
  onClick,
  type = 'button',
  style,
  children,
  ...rest
}) {
  const dim = disabled || loading;
  return (
    <button
      type={type}
      onClick={dim ? undefined : onClick}
      style={{
        ...btnBase,
        ...variants[variant],
        ...sizes[size],
        opacity: dim ? 0.55 : 1,
        cursor: dim ? 'not-allowed' : 'pointer',
        ...style,
      }}
      disabled={dim}
      {...rest}
    >
      {loading && <Spinner size={15} color="currentColor" />}
      {children}
    </button>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   CARD
   ═══════════════════════════════════════════════════════════════════════════ */

export function Card({ children, style, hover, ...rest }) {
  const [hovered, setHovered] = useState(false);
  return (
    <div
      onMouseEnter={() => hover && setHovered(true)}
      onMouseLeave={() => hover && setHovered(false)}
      style={{
        background: 'var(--surface)',
        border: '1px solid var(--border)',
        borderRadius: 'var(--radius-lg)',
        padding: 24,
        boxShadow: hovered ? 'var(--shadow-md)' : 'var(--shadow-sm)',
        transition: 'box-shadow 0.2s ease, transform 0.2s ease',
        transform: hovered ? 'translateY(-2px)' : 'none',
        ...style,
      }}
      {...rest}
    >
      {children}
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   INPUT
   ═══════════════════════════════════════════════════════════════════════════ */

export function Input({ label, error, style, ...props }) {
  return (
    <label style={{ display: 'block', marginBottom: 16, ...style }}>
      {label && (
        <span
          style={{
            display: 'block',
            fontSize: 13,
            fontWeight: 500,
            color: 'var(--text-secondary)',
            marginBottom: 6,
          }}
        >
          {label}
        </span>
      )}
      <input
        {...props}
        style={{
          width: '100%',
          padding: '9px 12px',
          borderRadius: 'var(--radius)',
          border: `1px solid ${error ? 'var(--danger)' : 'var(--border)'}`,
          fontFamily: 'var(--font-body)',
          fontSize: 14,
          outline: 'none',
          background: 'var(--surface)',
          color: 'var(--text-primary)',
          transition: 'border-color 0.15s ease, box-shadow 0.15s ease',
        }}
        onFocus={(e) => {
          e.target.style.borderColor = 'var(--primary)';
          e.target.style.boxShadow = '0 0 0 3px rgba(0,82,204,0.1)';
          props.onFocus?.(e);
        }}
        onBlur={(e) => {
          e.target.style.borderColor = error ? 'var(--danger)' : 'var(--border)';
          e.target.style.boxShadow = 'none';
          props.onBlur?.(e);
        }}
      />
      {error && (
        <span style={{ color: 'var(--danger)', fontSize: 12, marginTop: 4, display: 'block' }}>
          {error}
        </span>
      )}
    </label>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   SELECT
   ═══════════════════════════════════════════════════════════════════════════ */

export function Select({ label, error, children, style, ...props }) {
  return (
    <label style={{ display: 'block', marginBottom: 16, ...style }}>
      {label && (
        <span
          style={{
            display: 'block',
            fontSize: 13,
            fontWeight: 500,
            color: 'var(--text-secondary)',
            marginBottom: 6,
          }}
        >
          {label}
        </span>
      )}
      <select
        {...props}
        style={{
          width: '100%',
          padding: '9px 12px',
          borderRadius: 'var(--radius)',
          border: `1px solid ${error ? 'var(--danger)' : 'var(--border)'}`,
          fontFamily: 'var(--font-body)',
          fontSize: 14,
          background: 'var(--surface)',
          color: 'var(--text-primary)',
          cursor: 'pointer',
          outline: 'none',
          transition: 'border-color 0.15s ease',
        }}
      >
        {children}
      </select>
      {error && (
        <span style={{ color: 'var(--danger)', fontSize: 12, marginTop: 4, display: 'block' }}>
          {error}
        </span>
      )}
    </label>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   TEXTAREA
   ═══════════════════════════════════════════════════════════════════════════ */

export function Textarea({ label, error, style, ...props }) {
  return (
    <label style={{ display: 'block', marginBottom: 16, ...style }}>
      {label && (
        <span
          style={{
            display: 'block',
            fontSize: 13,
            fontWeight: 500,
            color: 'var(--text-secondary)',
            marginBottom: 6,
          }}
        >
          {label}
        </span>
      )}
      <textarea
        {...props}
        style={{
          width: '100%',
          padding: '9px 12px',
          borderRadius: 'var(--radius)',
          border: `1px solid ${error ? 'var(--danger)' : 'var(--border)'}`,
          fontFamily: 'var(--font-body)',
          fontSize: 14,
          outline: 'none',
          background: 'var(--surface)',
          color: 'var(--text-primary)',
          resize: 'vertical',
          minHeight: 80,
          transition: 'border-color 0.15s ease, box-shadow 0.15s ease',
        }}
        onFocus={(e) => {
          e.target.style.borderColor = 'var(--primary)';
          e.target.style.boxShadow = '0 0 0 3px rgba(0,82,204,0.1)';
          props.onFocus?.(e);
        }}
        onBlur={(e) => {
          e.target.style.borderColor = error ? 'var(--danger)' : 'var(--border)';
          e.target.style.boxShadow = 'none';
          props.onBlur?.(e);
        }}
      />
      {error && (
        <span style={{ color: 'var(--danger)', fontSize: 12, marginTop: 4, display: 'block' }}>
          {error}
        </span>
      )}
    </label>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   MODAL
   ═══════════════════════════════════════════════════════════════════════════ */

export function Modal({ open, onClose, title, children, width = 500 }) {
  useEffect(() => {
    if (!open) return;
    const onKey = (e) => e.key === 'Escape' && onClose?.();
    document.body.style.overflow = 'hidden';
    window.addEventListener('keydown', onKey);
    return () => {
      document.body.style.overflow = '';
      window.removeEventListener('keydown', onKey);
    };
  }, [open, onClose]);

  if (!open) return null;

  return (
    <div
      role="presentation"
      style={{
        position: 'fixed',
        inset: 0,
        background: 'rgba(23,43,77,0.5)',
        backdropFilter: 'blur(4px)',
        zIndex: 10000,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: 24,
      }}
      onClick={onClose}
    >
      <div
        role="dialog"
        onClick={(e) => e.stopPropagation()}
        style={{
          animation: 'fadeInScale 0.2s ease-out',
          background: 'var(--surface)',
          borderRadius: 'var(--radius-xl)',
          width: '100%',
          maxWidth: width,
          maxHeight: '90vh',
          overflow: 'auto',
          boxShadow: 'var(--shadow-xl)',
        }}
      >
        <div
          style={{
            padding: '18px 24px',
            borderBottom: '1px solid var(--border)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            position: 'sticky',
            top: 0,
            background: 'var(--surface)',
            zIndex: 1,
            borderRadius: 'var(--radius-xl) var(--radius-xl) 0 0',
          }}
        >
          <h2 style={{ fontSize: 18, fontWeight: 600 }}>{title}</h2>
          <button
            type="button"
            onClick={onClose}
            style={{
              border: 'none',
              background: 'var(--surface-2)',
              width: 32,
              height: 32,
              borderRadius: 'var(--radius)',
              fontSize: 18,
              cursor: 'pointer',
              color: 'var(--text-muted)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              transition: 'background 0.15s',
            }}
            onMouseEnter={(e) => (e.target.style.background = 'var(--danger-light)')}
            onMouseLeave={(e) => (e.target.style.background = 'var(--surface-2)')}
          >
            ×
          </button>
        </div>
        <div style={{ padding: 24 }}>{children}</div>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   TABLE
   ═══════════════════════════════════════════════════════════════════════════ */

export function Table({ cols, rows, loading, emptyMsg = 'No data found' }) {
  if (loading) {
    return (
      <div style={{ padding: 48, textAlign: 'center' }}>
        <Spinner size={32} />
        <p style={{ marginTop: 12, color: 'var(--text-muted)', fontSize: 14 }}>Loading...</p>
      </div>
    );
  }
  if (!rows?.length) {
    return (
      <div
        style={{
          padding: 48,
          textAlign: 'center',
          color: 'var(--text-muted)',
          fontSize: 14,
        }}
      >
        <div style={{ fontSize: 40, marginBottom: 8, opacity: 0.4 }}>📋</div>
        {emptyMsg}
      </div>
    );
  }
  return (
    <div style={{ overflowX: 'auto', borderRadius: 'var(--radius-lg)', border: '1px solid var(--border)' }}>
      <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
        <thead>
          <tr style={{ background: 'var(--surface-2)' }}>
            {cols.map((c) => (
              <th
                key={c.key}
                style={{
                  textAlign: 'left',
                  padding: '11px 16px',
                  fontSize: 12,
                  textTransform: 'uppercase',
                  letterSpacing: '0.05em',
                  fontWeight: 600,
                  color: 'var(--text-muted)',
                  borderBottom: '1px solid var(--border)',
                  whiteSpace: 'nowrap',
                }}
              >
                {c.label}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {rows.map((row, i) => (
            <tr
              key={row.key ?? row.id ?? i}
              style={{
                background: 'var(--surface)',
                transition: 'background 0.1s',
              }}
              onMouseEnter={(e) => (e.currentTarget.style.background = 'var(--surface-3)')}
              onMouseLeave={(e) => (e.currentTarget.style.background = 'var(--surface)')}
            >
              {cols.map((c) => (
                <td
                  key={c.key}
                  style={{
                    padding: '12px 16px',
                    borderBottom: '1px solid var(--border-light)',
                    verticalAlign: 'middle',
                    color: 'var(--text-primary)',
                  }}
                >
                  {c.render ? c.render(row) : row[c.key]}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   STAT CARD
